const fs = require('fs');
const path = require('path');

function readLogFile(filename) {
  // Validate input
  if (!filename || typeof filename !== 'string') {
    throw new Error('Invalid filename provided');
  }

  // Sanitize filename to prevent directory traversal attacks
  const sanitizedFilename = path.basename(filename);
  
  // Ensure the filename doesn't contain malicious patterns
  if (sanitizedFilename.includes('..') || sanitizedFilename.includes('/')) {
    throw new Error('Invalid filename: contains malicious patterns');
  }

  // Define log directory (secure location)
  const logDirectory = path.join(__dirname, 'logs');
  
  // Construct full file path
  const filePath = path.join(logDirectory, sanitizedFilename);
  
  // Verify file exists and is within log directory
  const resolvedPath = path.resolve(filePath);
  if (!resolvedPath.startsWith(logDirectory)) {
    throw new Error('Access denied: file must be within log directory');
  }
  
  // Check if file exists
  if (!fs.existsSync(resolvedPath)) {
    throw new Error('File not found');
  }
  
  // Read and return file contents
  try {
    const content = fs.readFileSync(resolvedPath, 'utf8');
    return content;
  } catch (error) {
    throw new Error('Failed to read file: ' + error.message);
  }
}